// src/pages/NewsPage.jsx
import React, { useEffect, useState } from "react";
import api from "../api/backend";

const NewsPage = () => {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchNews = async () => {
      try {
        const res = await api.get("/market-news");
        if (Array.isArray(res.data)) {
          setArticles(res.data);
        } else if (res.data && res.data.error) {
          setError(res.data.error);
        } else {
          setArticles([]);
        }
      } catch (err) {
        console.error(err);
        setError("Failed to load news.");
      } finally {
        setLoading(false);
      }
    };

    fetchNews();
  }, []);

  return (
    <div className="page-shell">
      <header className="header">
        <h1>Market News</h1>
        <p>Latest headlines from Yahoo Finance.</p>
      </header>

      <section className="results-panel">
        {loading && <p className="placeholder">Fetching latest news…</p>}
        {error && <div className="error-box">{error}</div>}

        {!loading && !error && articles.length === 0 && (
          <p className="placeholder">
            No articles available right now. Try again in a few minutes.
          </p>
        )}

        {!loading && !error && articles.length > 0 && (
          <div className="news-grid">
            {articles.map((a, idx) => (
              <article key={idx} className="news-card">
                <div className="news-card-header">
                  <span className="news-source">{a.source || "Yahoo Finance"}</span>
                  {a.published && (
                    <span className="news-time">{a.published}</span>
                  )}
                </div>

                <a
                  href={a.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="news-title"
                >
                  {a.title}
                </a>

                {a.summary && (
                  <p className="news-summary">{a.summary}</p>
                )}

                <div className="news-footer">
                  <a
                    href={a.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="news-link-btn"
                  >
                    Read article
                  </a>
                </div>
              </article>
            ))}
          </div>
        )}
      </section>
    </div>
  );
};

export default NewsPage;
